const ZM_MoveData& ZM_GetMoveData(ZM_MOVE_ID eId)
{
	Zenith_Assert(eId < ZM_MOVE_COUNT, "ZM_GetMoveData: move id out of range (%u)", (u_int)eId);
	return s_axMoves[eId];
}

u_int ZM_GetMoveCount()
{
	return ZM_MOVE_COUNT;
}

const char* ZM_GetMoveName(ZM_MOVE_ID eId)
{
	if (eId >= ZM_MOVE_COUNT)
	{
		return "NONE";
	}
	return s_axMoves[eId].m_szName;
}

const char* ZM_MoveCategoryToString(ZM_MOVE_CATEGORY eCategory)
{
	switch (eCategory)
	{
	case ZM_MOVE_CATEGORY_PHYSICAL: return "PHYSICAL";
	case ZM_MOVE_CATEGORY_SPECIAL:  return "SPECIAL";
	case ZM_MOVE_CATEGORY_STATUS:   return "STATUS";
	default:                        return "INVALID";
	}
}

const char* ZM_MoveTargetToString(ZM_MOVE_TARGET eTarget)
{
	switch (eTarget)
	{
	case ZM_MOVE_TARGET_OPPONENT: return "OPPONENT";
	case ZM_MOVE_TARGET_SELF:     return "SELF";
	case ZM_MOVE_TARGET_FIELD:    return "FIELD";
	default:                      return "INVALID";
	}
}
